#include <algorithm>
#include <utility>
using namespace std;

struct TrieNode {
    TrieNode* child[2];
    TrieNode() : child{nullptr, nullptr} {}
};

class Trie {
public:
    TrieNode* root;
    Trie() {
        root = new TrieNode();
    }

    void insert(long long val) {
        TrieNode* cur = root;
        for (int i=40; i>=0; i--) {
            int b = (val >> i) & 1;
            if (cur->child[b] == nullptr) {
                cur->child[b] = new TrieNode();
            }
            cur = cur->child[b];
        }
    }

    bool query(long long a, long long x) {
        TrieNode* cur = root;
        for (int i=40; i>=0; i--) {
            if (cur == nullptr) {
                return false;
            }
            int a_i = (a >> i) & 1;
            int x_i = (x >> i) & 1;
            if (x_i == 1) {
                if (cur->child[a_i] != nullptr) {
                    return true;
                }
                cur = cur->child[1 ^ a_i];
            } else {
                cur = cur->child[a_i];
            }
        }
        return (cur != nullptr);
    }
};

